// Trait for extractors that can work synchronously (WASM-compatible).
//
// This trait defines the synchronous extraction interface for WASM targets and other
// environments where async/tokio runtimes are not available or desirable.
//
// # Implementation
//
// Extractors that need to support WASM should implement this trait in addition to
// the async `DocumentExtractor` trait. This allows the same extractor to work in both
// environments by delegating to the sync implementation.
//
// # MIME Type Validation
//
// The `mime_type` parameter is guaranteed to be already validated.
//
// # Example
//
// ```rust,ignore
// impl SyncExtractor for PlainTextExtractor {
// fn extract_sync(&self, content: &[u8], config: &ExtractionConfig) -> Result<ExtractionResult> {
// let text = String::from_utf8_lossy(content).to_string();
// Ok(ExtractionResult {
// content: text,
// mime_type: "text/plain".to_string(),
// metadata: Metadata::default(),
// tables: vec![],
// detected_languages: None,
// chunks: None,
// images: None,
// })
// }
// }
// ```
type SyncExtractor struct {
    ptr unsafe.Pointer
}

// Free releases the resources held by this handle.
func (h *SyncExtractor) Free() {
    if h.ptr != nil {
        C.kreuzberg_sync_extractor_free((*C.KREUZBERGSyncExtractor)(h.ptr))
        h.ptr = nil
    }
}


