// assert_eq!(resolve_thread_budget(Some(&config)), 4);
// assert!(resolve_thread_budget(None) >= 1);
// ```
func ResolveThreadBudget(config ...*string) *uint {
    var configVal *string
    if len(config) > 0 {
        configVal = config[0]
    }
    cConfigVal := C.CString(configVal)
    defer C.free(unsafe.Pointer(cConfigVal))

    ptr := C.kreuzberg_resolve_thread_budget(cConfigVal)
    return func() *uint { v := uint(ptr); return &v }()
}


