// Process is a method.
func (r *ChunkingProcessor) Process(result ExtractionResult, config ExtractionConfig) error {
    resultCh := make(chan error, 1)
    errCh := make(chan error, 1)
    go func() {
        result, err := r.processSync(result, config)
        if err != nil {
            errCh <- err
        } else {
            resultCh <- result
        }
    }()
    return resultCh, errCh
}


